module srt_divider (
    input [3:0] obf_dividend,
    input [3:0] divisor,
    output reg [3:0] quotient,
    output reg [3:0] remainder
);
    always @(*) begin
        if (divisor == 4'b0000) begin
            quotient = 4'b0000;
            remainder = 4'b0000;
        end else begin
            quotient = obf_dividend / divisor;
            remainder = obf_dividend % divisor;
        end
    end
endmodule
